import{_ as e,a,b as n}from"./chunks/管理端登录界面.yuERlcJ6.js";import{_ as t,o,c as l,a2 as c}from"./chunks/framework.DnrXFDHb.js";const b=JSON.parse('{"title":"Authentication và Login Device Management","description":"","frontmatter":{},"headers":[],"relativePath":"vi-VN/Safety/authentication-and-login-devices.md","filePath":"vi-VN/Safety/authentication-and-login-devices.md","lastUpdated":1781962217000}'),s={name:"vi-VN/Safety/authentication-and-login-devices.md"};function d(r,i,h,u,p,g){return o(),l("div",null,[...i[0]||(i[0]=[c('<h1 id="authentication-va-login-device-management" tabindex="-1">Authentication và Login Device Management <a class="header-anchor" href="#authentication-va-login-device-management" aria-label="Permalink to &quot;Authentication và Login Device Management&quot;">​</a></h1><p><code>Authentication Management</code> và <code>Login Device Management</code> bảo vệ ImgBed admin panel, public upload entry và WebDAV access.</p><p>Dùng trang này để đặt access credentials, xem các devices đã sign in và revoke sessions cũ khi cần.</p><h2 id="cau-hinh-o-đau" tabindex="-1">Cấu hình ở đâu <a class="header-anchor" href="#cau-hinh-o-đau" aria-label="Permalink to &quot;Cấu hình ở đâu&quot;">​</a></h2><p>Mở admin panel, rồi vào:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Security Settings</span></span></code></pre></div><p>Trang này có hai khu vực chính:</p><ul><li>Authentication Management</li><li>Login Device Management</li></ul><p><img src="'+e+'" alt="Authentication management" loading="lazy"></p><h2 id="authentication-management-lam-gi" tabindex="-1">Authentication Management làm gì <a class="header-anchor" href="#authentication-management-lam-gi" aria-label="Permalink to &quot;Authentication Management làm gì&quot;">​</a></h2><p>Authentication Management lưu access credentials.</p><p>Có hai loại:</p><ul><li>User-side authentication</li><li>Admin-side authentication</li></ul><h2 id="user-side-authentication" tabindex="-1">User-Side Authentication <a class="header-anchor" href="#user-side-authentication" aria-label="Permalink to &quot;User-Side Authentication&quot;">​</a></h2><p>User-side authentication chính là upload password.</p><p>Sau khi đặt upload password, visitors thông thường phải nhập password trước khi dùng upload page. Tính năng này hữu ích khi bạn không muốn public upload page mở hoàn toàn cho mọi người.</p><p><img src="'+a+'" alt="User login page" loading="lazy"></p><h3 id="đat-upload-password" tabindex="-1">Đặt Upload Password <a class="header-anchor" href="#đat-upload-password" aria-label="Permalink to &quot;Đặt Upload Password&quot;">​</a></h3><p>Khi upload password đã được cấu hình:</p><ul><li>Visitors phải nhập password trước khi dùng upload page.</li><li>Chỉ upload được sau khi password được chấp nhận.</li><li>Nếu user-side device sessions được bật, ImgBed sẽ ghi lại user-side device đó.</li></ul><p>Đổi upload password sẽ làm các user-side sessions cũ invalid. Visitors cần nhập password mới lại.</p><h2 id="admin-side-authentication" tabindex="-1">Admin-Side Authentication <a class="header-anchor" href="#admin-side-authentication" aria-label="Permalink to &quot;Admin-Side Authentication&quot;">​</a></h2><p>Admin-side authentication dùng admin username và password.</p><p>Phần này bảo vệ admin panel. Với production use, bạn nên luôn cấu hình.</p><p><img src="'+n+'" alt="Admin login page" loading="lazy"></p><h3 id="đat-admin-credentials" tabindex="-1">Đặt Admin Credentials <a class="header-anchor" href="#đat-admin-credentials" aria-label="Permalink to &quot;Đặt Admin Credentials&quot;">​</a></h3><p>Khi admin username và password đã được cấu hình:</p><ul><li>Mở admin panel sẽ yêu cầu login.</li><li>Login thành công sẽ tạo admin device record.</li><li>Bạn có thể review, clean up hoặc force devices offline trong Login Device Management.</li></ul><p>Đổi admin username hoặc password sẽ làm admin sessions cũ invalid. Bạn cần sign in lại.</p><h2 id="login-device-management-lam-gi" tabindex="-1">Login Device Management làm gì <a class="header-anchor" href="#login-device-management-lam-gi" aria-label="Permalink to &quot;Login Device Management làm gì&quot;">​</a></h2><p>Login Device Management hiển thị các devices đã sign in.</p><p>Nó giúp kiểm tra:</p><ul><li>Devices nào đã access admin panel.</li><li>Devices nào đã access user-side upload page.</li><li>WebDAV clients nào đã connected.</li><li>Device session còn valid hay không.</li><li>Có nên force offline devices cũ hay không.</li></ul><p>Trang có ba tabs:</p><ul><li>Admin</li><li>User</li><li>WebDAV</li></ul><h2 id="global-cookie-security" tabindex="-1">Global Cookie Security <a class="header-anchor" href="#global-cookie-security" aria-label="Permalink to &quot;Global Cookie Security&quot;">​</a></h2><p>Ở đầu Login Device Management, bạn có thể cấu hình global cookie behavior.</p><h3 id="user-cookie-lifetime" tabindex="-1">User Cookie Lifetime <a class="header-anchor" href="#user-cookie-lifetime" aria-label="Permalink to &quot;User Cookie Lifetime&quot;">​</a></h3><p>Kiểm soát user-side login có thể active trong bao nhiêu ngày.</p><p>Ví dụ, nếu đặt 14 days, visitors thường không cần nhập lại upload password trong vòng 14 ngày.</p><h3 id="admin-cookie-lifetime" tabindex="-1">Admin Cookie Lifetime <a class="header-anchor" href="#admin-cookie-lifetime" aria-label="Permalink to &quot;Admin Cookie Lifetime&quot;">​</a></h3><p>Kiểm soát admin login có thể active trong bao nhiêu ngày.</p><p>Ví dụ, nếu đặt 14 days, administrators thường không cần sign in lại trong vòng 14 ngày.</p><h3 id="secure-mode" tabindex="-1">Secure Mode <a class="header-anchor" href="#secure-mode" aria-label="Permalink to &quot;Secure Mode&quot;">​</a></h3><p>Khi Secure mode được bật, browsers chỉ gửi login cookies qua HTTPS.</p><p>Hãy bật cho production HTTPS sites. Không bật khi test local HTTP, nếu không có thể gặp tình trạng &quot;login thành công, nhưng refresh lại bị logout&quot;.</p><h2 id="admin-login-devices" tabindex="-1">Admin Login Devices <a class="header-anchor" href="#admin-login-devices" aria-label="Permalink to &quot;Admin Login Devices&quot;">​</a></h2><p>Admin tab hiển thị devices đã sign in vào admin panel.</p><p>Device records chỉ xuất hiện sau khi admin credentials được cấu hình và admin panel được access qua login.</p><p>Mỗi device card có thể hiển thị:</p><ul><li>Device và browser information</li><li>First login IP</li><li>Last active IP</li><li>Login time</li><li>Last active time</li><li>Expiration time</li><li>Current status</li></ul><p>Nếu thấy device lạ, dùng <code>Force Offline</code> để invalid nó.</p><h2 id="clean-up-old-devices" tabindex="-1">Clean Up Old Devices <a class="header-anchor" href="#clean-up-old-devices" aria-label="Permalink to &quot;Clean Up Old Devices&quot;">​</a></h2><p><code>Clean Up Old Devices</code> xóa hàng loạt login records cũ trong tab hiện tại.</p><p>Dùng khi bạn nghi ngờ sessions cũ vẫn còn active trên devices khác.</p><h2 id="force-offline" tabindex="-1">Force Offline <a class="header-anchor" href="#force-offline" aria-label="Permalink to &quot;Force Offline&quot;">​</a></h2><p><code>Force Offline</code> invalid một device session.</p><p>Sau khi device bị force offline:</p><ul><li>Admin devices phải sign in lại.</li><li>User-side devices phải nhập lại upload password.</li><li>WebDAV clients phải authenticate lại.</li></ul><p>Expired hoặc invalid devices cũng có thể bị xóa.</p><h2 id="sign-out-current-device" tabindex="-1">Sign Out Current Device <a class="header-anchor" href="#sign-out-current-device" aria-label="Permalink to &quot;Sign Out Current Device&quot;">​</a></h2><p>Current device card được đánh dấu <code>Current Device</code>.</p><p>Sau khi sign out current device:</p><ul><li>Current admin session bị sign out.</li><li>Current user-side session bị sign out.</li></ul><p>Bạn cần sign in lại trước khi tiếp tục dùng khu vực đó.</p>',65)])])}const f=t(s,[["render",d]]);export{b as __pageData,f as default};
